import {
  circle, ellipse, rectangle, rounded_rectangle, polygon, triangle,
  segment, arc, ring, trapezoid,
  union, intersection, difference, dilate, shell,
  render,
} from '../../src/index.js';

// --- Palette ---
const SKY_TOP     = [58,  90, 130];
const SKY_MID     = [120, 160, 190];
const SKY_BOTTOM  = [210, 200, 175];
const SEA_DARK    = [30,  70, 110];
const SEA_MID     = [55, 105, 150];
const SEA_LIGHT   = [100, 155, 185];
const FOAM        = [225, 235, 240];
const CLIFF_DARK  = [80,  70,  55];
const CLIFF_MID   = [120, 108,  88];
const GRASS       = [85, 110,  65];
const TOWER_BASE  = [230, 220, 205];
const TOWER_BAND  = [195,  45,  35];   // classic red stripe
const LANTERN_C   = [255, 230, 120];
const CAP_C       = [40,  40,  40];
const OUTLINE     = [22,  18,  14];
const MOON_C      = [250, 240, 190];
const STAR_C      = [240, 235, 200];

// ─── Sky & atmospheric layers ──────────────────────────────────────────────

const skyRect = rectangle([3.0, 3.0], [0, 0]);

// Moon (no outline, atmospheric glow)
const moon = circle(0.075, [-0.70, 0.72]);
const moonGlow = circle(0.12, [-0.70, 0.72]);

// Stars – scattered dots via small circles
function star(x, y, r = 0.008) { return circle(r, [x, y]); }
const stars = union(
  star(-0.82, 0.95), star(-0.55, 0.88), star(-0.30, 1.00),
  star( 0.10, 0.93), star( 0.42, 0.85), star( 0.72, 0.92),
  star( 0.90, 1.05), star(-0.92, 0.70), star(-0.40, 0.78),
  star( 0.55, 0.78), star( 0.20, 1.02), star(-0.65, 1.08),
);

// Horizon fog band
const horizonFog = intersection(
  rectangle([3.0, 0.18], [0, -0.12]),
  skyRect,
);

// ─── Sea ───────────────────────────────────────────────────────────────────

// Sea fill – everything below the horizon line (-0.20)
const seaFill = intersection(
  rectangle([3.0, 1.6], [0, -1.10]),
  skyRect,
);

// Wave hints – thin arcs / elongated ellipses
function wave(cx, cy, w, h) {
  return intersection(
    ellipse(w, h, [cx, cy]),
    rectangle([w * 2.2, h * 1.0], [cx, cy + h * 0.4]), // top half only
  );
}
const waves = union(
  wave(-0.90, -0.28, 0.28, 0.025),
  wave(-0.50, -0.34, 0.22, 0.020),
  wave( 0.55, -0.32, 0.26, 0.022),
  wave( 0.85, -0.25, 0.20, 0.018),
  wave( 0.30, -0.40, 0.18, 0.016),
  wave(-0.20, -0.44, 0.24, 0.018),
);

// Moonlight path on water
const moonPath = intersection(
  ellipse(0.09, 0.38, [-0.68, -0.50]),
  seaFill,
);

// ─── Cliff / rocky promontory ───────────────────────────────────────────────

const cliff = polygon([
  [-1.20, -1.20],
  [-1.20, -0.30],
  [-0.92, -0.25],
  [-0.70, -0.32],
  [-0.52, -0.22],  // top of cliff
  [-0.30, -0.28],
  [-0.10, -0.20],  // base of lighthouse
  [ 0.30, -0.25],
  [ 0.50, -0.38],
  [ 0.60, -1.20],
]);

const grassTop = intersection(
  union(
    rectangle([0.70, 0.04], [-0.45, -0.20]),
    ellipse(0.38, 0.06, [-0.52, -0.21]),
  ),
  cliff,
);

// ─── Lighthouse tower ──────────────────────────────────────────────────────

// Main tower body – slightly tapered (trapezoid-ish via a union)
// Base wider than top: use a simple rectangle + tiny triangle cap trick
const towerShaft = union(
  // bottom wider section
  rectangle([0.14, 0.58], [0.09, -0.00]),
  // taper: difference off corners using shifted rectangles is complex;
  // approximate with a slight trapezoid polygon
  polygon([
    [ 0.09 - 0.07,  -0.29],
    [ 0.09 + 0.07,  -0.29],
    [ 0.09 + 0.055,  0.29],
    [ 0.09 - 0.055,  0.29],
  ]),
);

// Red stripe bands (decoration clipped to tower)
function stripe(cy, h) {
  return intersection(towerShaft, rectangle([0.20, h], [0.09, cy]));
}
const band1 = stripe(-0.10, 0.065);
const band2 = stripe( 0.10, 0.065);

// Gallery / balcony ring
const gallery = union(
  rectangle([0.185, 0.025], [0.09, 0.295]),
  rectangle([0.155, 0.020], [0.09, 0.270]),
);

// Lantern room (bright glazed octagon approximation: circle)
const lanternRoom = circle(0.065, [0.09, 0.39]);
const lanternGlow = circle(0.10, [0.09, 0.39]);

// Cap / roof
const cap = polygon([
  [0.09 - 0.072, 0.420],
  [0.09 + 0.072, 0.420],
  [0.09,         0.530],
]);

// Light beam – two thin wedge polygons radiating from lantern
const beamLeft = intersection(
  polygon([
    [0.09, 0.39],
    [-0.35, 0.75],
    [-0.55, 0.65],
  ]),
  rectangle([3.0, 3.0], [0, 0]),
);
const beamRight = intersection(
  polygon([
    [0.09, 0.39],
    [0.50, 0.68],
    [0.35, 0.78],
  ]),
  rectangle([3.0, 3.0], [0, 0]),
);

// Door at base
const door = rounded_rectangle([0.035, 0.055], 0.015, [0.09, -0.255]);
// Windows
function win(cy) {
  return rounded_rectangle([0.028, 0.040], 0.012, [0.09, cy]);
}
const windows = union(win(-0.14), win(0.05), win(0.20));

// Rocks at cliff base
const rock1 = ellipse(0.08, 0.04, [-0.18, -0.32]);
const rock2 = ellipse(0.05, 0.03, [ 0.22, -0.35]);
const rock3 = ellipse(0.06, 0.025, [ 0.38, -0.30]);

// ─── Compositing helpers ───────────────────────────────────────────────────

// Full tower silhouette for outlining
const towerFull = union(towerShaft, gallery, lanternRoom, cap);

// ─── Layers (bottom to top) ─────────────────────────────────────────────────

const layers = [
  // Sky gradient approximated with two rectangles
  { sdf: intersection(rectangle([3,2],[0, 0.8]), skyRect), color: SKY_TOP    },
  { sdf: intersection(rectangle([3,1.2],[0, 0.0]), skyRect), color: SKY_MID  },
  { sdf: intersection(rectangle([3,0.8],[0,-0.4]), skyRect), color: SKY_BOTTOM },

  // Moon glow (soft, no outline)
  { sdf: moonGlow, color: [200, 200, 160] },
  { sdf: moon,     color: MOON_C          },

  // Stars
  { sdf: stars, color: STAR_C },

  // Horizon fog
  { sdf: horizonFog, color: [200, 200, 185] },

  // Sea layers
  { sdf: seaFill,   color: SEA_DARK  },
  { sdf: intersection(rectangle([3,0.5],[0,-0.55]), skyRect), color: SEA_MID   },
  { sdf: moonPath,  color: SEA_LIGHT },
  { sdf: waves,     color: FOAM      },

  // Cliff – outline then fill
  { sdf: dilate(cliff, 0.022), color: OUTLINE    },
  { sdf: cliff,                color: CLIFF_DARK },
  { sdf: intersection(cliff, rectangle([3,0.18],[-0.40,-0.22])), color: CLIFF_MID },
  { sdf: grassTop,             color: GRASS      },

  // Rocks
  { sdf: union(rock1,rock2,rock3), color: CLIFF_DARK },

  // Light beams (translucent suggestion – light yellow)
  { sdf: beamLeft,  color: [240, 235, 180] },
  { sdf: beamRight, color: [240, 235, 180] },

  // Tower – outline
  { sdf: dilate(towerFull, 0.026), color: OUTLINE    },
  // Tower – white base
  { sdf: towerShaft,               color: TOWER_BASE },
  // Red stripe bands
  { sdf: band1, color: TOWER_BAND },
  { sdf: band2, color: TOWER_BAND },
  // Gallery
  { sdf: dilate(gallery, 0.010), color: OUTLINE  },
  { sdf: gallery,                color: CAP_C    },
  // Lantern glow
  { sdf: lanternGlow, color: [255, 245, 170] },
  // Lantern room outline + fill
  { sdf: dilate(lanternRoom, 0.014), color: OUTLINE   },
  { sdf: lanternRoom,                color: LANTERN_C },
  // Cap
  { sdf: dilate(cap, 0.014), color: OUTLINE },
  { sdf: cap,                color: CAP_C   },
  // Door & windows cut out (dark)
  { sdf: door,    color: OUTLINE },
  { sdf: windows, color: OUTLINE },
];

// ─── Render ────────────────────────────────────────────────────────────────

const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.2,
  background: { top: [35, 55, 95], bottom: [55, 85, 120] },
});
```

---

**Composition notes:**

The scene is structured as four depth planes — night sky, sea, cliff, and lighthouse — rendered bottom-to-top so each layer naturally occludes what's behind it. The tower uses a **graded outline hierarchy** (main shaft t=0.026, gallery/lantern t=0.010–0.014) to push the tower forward in perceived depth. Red stripe bands are clipped to the tower polygon via `intersection`, the canonical "decoration within silhouette" idiom from `cathedral.js`. The two light beams are semi-transparent pale-yellow wedge polygons that taper from the lantern room, evoking the sweeping beam without full opacity — suggested light rather than literal rays. Moonlight on the water is an ellipse clipped to the sea fill, picking up the classic seascape painter trick of a narrow bright path from source to viewer. The cliff polygon is hand-traced with a rough natural edge; the mid-tone horizontal slice through it creates the illusion of layered rock strata.
